import{_ as i,V as t,W as d,X as a,Y as e,Z as l,a1 as s,y as r}from"./framework.42bbefdb.js";const c={},o=s(`<h1 id="git-配置多用户" tabindex="-1"><a class="header-anchor" href="#git-配置多用户" aria-hidden="true">#</a> Git 配置多用户</h1><h2 id="_1-清除全局配置" tabindex="-1"><a class="header-anchor" href="#_1-清除全局配置" aria-hidden="true">#</a> 1 清除全局配置</h2><p>在正式配置之前，先查看是否存在全局配置，执行命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">--global</span> <span class="token parameter variable">--list</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>`,4),u={href:"http://user.name",target:"_blank",rel:"noopener noreferrer"},p=s(`<div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> config <span class="token parameter variable">--global</span> <span class="token parameter variable">--unset</span> user.name
<span class="token function">git</span> config <span class="token parameter variable">--global</span> <span class="token parameter variable">--unset</span> user.email
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_2-生成密钥对" tabindex="-1"><a class="header-anchor" href="#_2-生成密钥对" aria-hidden="true">#</a> 2 生成密钥对</h2><p>钥对的保存位置默认在 <code>~/.ssh</code> 目录下，我们先删除这个目录中已存在的 id_rsa、id_rsa.pub 之类的公钥和密钥文件。</p><p>开始生成 github 上的仓库钥对，通过 -C 参数填写 github 的邮箱：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> ~/.ssh
ssh-keygen <span class="token parameter variable">-t</span> rsa <span class="token parameter variable">-C</span> <span class="token string">&quot;xxxx@xxx.com&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>此时会提示</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Generating public/private rsa key pair.
Enter file in which to save the key (/c/Users/fangtao/.ssh/id_rsa):
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>在这里输入公钥的名字，默认是 id_rsa，为了和后面的 gitlab配置区分，这里输入 id_rsa_github，输入完毕后，一路回车，钥对就生成完毕了。</p><p>下面开始生成 gitlab 上的仓库钥对，步骤和上面一样。</p><h2 id="_3-添加-ssh-keys" tabindex="-1"><a class="header-anchor" href="#_3-添加-ssh-keys" aria-hidden="true">#</a> 3 添加 SSH Keys</h2><p>将 id_rsa_github.pub 和 id_rsa_gitlab.pub 内容分别添加到 github 和 gitlab 的 SSH Keys 中，这里就不啰嗦了。</p><h2 id="_4-添加私钥" tabindex="-1"><a class="header-anchor" href="#_4-添加私钥" aria-hidden="true">#</a> 4 添加私钥</h2><p>在上一步中，我们已经将公钥添加到了 github 或者 gitlab 服务器上，我们还需要将私钥添加到本地中，不然无法使用。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 将 GitHub 私钥添加到本地</span>
ssh-add ~/.ssh/id_rsa_github
<span class="token comment"># 将 GitLab 私钥添加到本地</span>
ssh-add ~/.ssh/id_rsa_gitlab
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>此时如果提示</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Could not open a connection to your authentication agent.
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>执行以下命令后，重新添加私钥</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>ssh-agent <span class="token function">bash</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="_5-管理密钥" tabindex="-1"><a class="header-anchor" href="#_5-管理密钥" aria-hidden="true">#</a> 5 管理密钥</h2><p>通过以上步骤，公钥、密钥分别被添加到 git 服务器和本地了。下面我们需要在本地创建一个密钥配置文件，通过该文件，实现根据仓库的 remote 链接地址自动选择合适的私钥。</p><p>编辑 ~/.ssh 目录下的 config 文件，如果没有，请创建。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> ~/.ssh/config
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>配置内容如下：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>Host github.com
HostName github.com
User github_user_name
PreferredAuthentications publickey
IdentityFile ~/.ssh/id_rsa_github

Host gitlab.xxx.com
HostName gitlab.xxx.com
User gitlab_user_name
PreferredAuthentications publickey
IdentityFile ~/.ssh/id_rsa_gitlab
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>该文件分为多个用户配置，每个用户配置包含以下几个配置项：</p><ul><li>Host：仓库网站的别名。推荐和HostName一致，否则在 git clone 时可能需要将 remote 地址中 HostName 替换为别名</li><li>HostName：仓库网站的域名（PS：IP 地址应该也可以）</li><li>User：仓库网站上的用户名，如果使用用户名不成功可以用邮箱</li><li>IdentityFile：私钥的绝对路径</li></ul><p>注： Host 就是可以替代 HostName 来使用的别名，比如我 github 上某个仓库的 clone 地址为：git@github.com:github_user_name/express.git</p><p>那么使用 Host 后就是：git@github:github_user_name/express.git</p><p>咳咳，反正我觉得没啥用，毕竟 remote 地址都是直接复制下来的，没人会手敲吧？</p><p>可以用 ssh -T 命令检测下配置的 Host 是否是连通的：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ssh</span> <span class="token parameter variable">-T</span> git@github.com
<span class="token function">ssh</span> <span class="token parameter variable">-T</span> git@gitlab.xxx.com
Welcome to GitLab, @lemon<span class="token operator">!</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_6-仓库配置" tabindex="-1"><a class="header-anchor" href="#_6-仓库配置" aria-hidden="true">#</a> 6 仓库配置</h2><h3 id="_6-1-按项目配置" tabindex="-1"><a class="header-anchor" href="#_6-1-按项目配置" aria-hidden="true">#</a> 6.1 按项目配置</h3><p>完成以上配置后，已经基本完成了所有配置。分别进入附属于 github 和 gitlab 的仓库，此时都可以进行 git 操作了。但是别急，如果你此时提交仓库修改后，你会发现提交的用户名变成了你的系统主机名。</p><p>这是因为 git 的配置分为三级别，System 、 Global 、 Local。System 即系统级别，Global 为配置的全局，Local 为仓库级别，优先级是 Local &gt; Global &gt; System。</p><p>因为我们并没有给仓库配置用户名，又在一开始清除了全局的用户名，因此此时你提交的话，就会使用 System 级别的用户名，也就是你的系统主机名了。</p><p>因此我们需要为每个仓库单独配置用户名信息，假设我们要配置 github 的某个仓库，进入该仓库后，执行：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>git config --local user.name &quot;github_user_name&quot;
git config --local user.email &quot;github_user_name@foxmail.com&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>执行完毕后，通过以下命令查看本仓库的所有配置信息：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>git config --local --list
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>至此你已经配置好了 Local 级别的配置了，此时提交该仓库的代码，提交用户名就是你设置的 Local 级别的用户名了。</p><h3 id="_6-2-按文件夹配置" tabindex="-1"><a class="header-anchor" href="#_6-2-按文件夹配置" aria-hidden="true">#</a> 6.2 按文件夹配置</h3><p>用项目配置的方法虽然可以实现不同项目配置不同信息，但每个项目都配置一遍就太麻烦了，而且会经常出现漏配的情况，有把公司信息暴露到公共空间中风险。使用git的<code>Conditional Includes</code>可以解决这个问题。<code>Conditional Includes</code>可以针对文件夹来配置，配置方法如下：</p><p>在<code>~/</code>目录下，新建 <code>.gitconfig_gitlab</code> 文件，编辑内容如下</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[user]
    name = gitlab_name
    email = gitlab_mail@xxx.com
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>继续新建 <code>.gitconfig_github</code> 文件，编辑内容如下</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[user]
    name = github_name
    email = github_mail@xxx.com
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>全局通用配置文件<code>~/.gitconfig</code>里面的内容是：</p><div class="language-ini line-numbers-mode" data-ext="ini"><pre class="language-ini"><code><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">includeIf &quot;gitdir:~/gitlab-workspace/&quot;</span><span class="token punctuation">]</span></span>
    <span class="token key attr-name">path</span> <span class="token punctuation">=</span> <span class="token value attr-value">.gitconfig-self</span>
<span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">includeIf &quot;gitdir:~/github_workspace/&quot;</span><span class="token punctuation">]</span></span>
    <span class="token key attr-name">path</span> <span class="token punctuation">=</span> <span class="token value attr-value">.gitconfig-work</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>gitdir:</code>后面设置的是你想设置的文件夹目录，使用的是glob匹配模式，记得要以<code>/</code>结尾，否则不会生效（以<code>/</code>结尾，<code>**</code>会被自动添加上，比如<code>you/dir/</code> 会变成 <code>you/dir/**</code>，这样才能生效到所有子文件夹）。</p><p>项目配置 &gt; 文件夹配置 &gt; 全局配置</p>`,51);function b(m,v){const n=r("ExternalLinkIcon");return t(),d("div",null,[o,a("p",null,[e("如果发现其中有 "),a("a",u,[e("user.name"),l(n)]),e(" 和 user.email 信息，执行以下命令将其清除")]),p])}const h=i(c,[["render",b],["__file","settings.html.vue"]]);export{h as default};
